+fn dedupe_preserving_order(values: &[String]) -> Vec<String> {
+    let mut seen = HashSet::new();
+    let mut deduped = Vec::with_capacity(values.len());
+    for value in values {
+        if seen.insert(value.clone()) {
+            deduped.push(value.clone());
+        }
+    }
+    deduped
+}
